"""
Parameterized generator for GH646_napari_6965.

Source PR:    https://github.com/napari/napari/pull/6965
Source Issue: https://github.com/napari/napari/issues/6643

Seed varies: renames 'about' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH646_napari_6965'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH646_napari_6965'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('about', 'about' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH646_napari_6965',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'napari/napari',
                "pr_number": 6965,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/napari/napari/pull/6965",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'napari/_app_model/_tests/test_context.py': "from unittest.mock import Mock\n\nimport pytest\n\nfrom napari._app_model.context._context import (\n    ContextMapping,\n    create_context,\n    get_context,\n)\n\n\ndef test_simple_mapping():\n    data = {'a': 1, 'b': 2}\n    mapping = ContextMapping(data)\n    assert mapping['a'] == 1\n    assert mapping['b'] == 2\n    assert 'a' in mapping\n    assert list(mapping) == ['a', 'b']\n    assert len(mapping) == 2\n\n\ndef test_missed_key():\n    data = {'a': 1, 'b': 2}\n    mapping = ContextMapping(data)\n    with pytest.raises(KeyError):\n        mapping['c']\n\n\ndef test_callable_value():\n    data = {'a': 1, 'b': Mock(return_value=2)}\n    mapping = ContextMapping(data)\n    assert mapping['a'] == 1\n    assert mapping['b'] == 2\n    assert mapping['b'] == 2  # it is important to use [] twice in this test\n    data['b'].assert_called_once()\n\n\ndef test_context_integration():\n    obj = {1, 2, 3}\n    ctx = create_context(obj)\n    ctx['a'] = 1\n    ctx['b'] = Mock(return_value=2)\n\n    assert isinstance(get_context(obj), ContextMapping)\n    mapping = get_context(obj)\n    assert mapping['a'] == 1\n    assert mapping['b'] == 2\n    assert mapping['b'] == 2  # it is important to use [] twice in this test\n    ctx['b'].assert_called_once()\n\n    mapping2 = get_context(obj)\n    assert mapping2['b'] == 2\n    assert ctx['b'].call_count == 2\n    assert mapping2['b'] == 2\n    assert ctx['b'].call_count == 2\n",
            'napari/_app_model/context/_context.py': 'from __future__ import annotations\n\nfrom typing import TYPE_CHECKING, Any, Final, Optional\n\nfrom app_model.expressions import (\n    Context,\n    create_context as _create_context,\n    get_context,\n)\n\nfrom napari.utils.translations import trans\n\nif TYPE_CHECKING:\n    from napari.utils.events import Event\n\n__all__ = [\'create_context\', \'get_context\', \'Context\', \'SettingsAwareContext\']\n\n\nclass SettingsAwareContext(Context):\n    """A special context that allows access of settings using `settings.`\n\n    This takes no parents, and will always be a root context.\n    """\n\n    _PREFIX: Final[str] = \'settings.\'\n\n    def __init__(self) -> None:\n        super().__init__()\n        from napari.settings import get_settings\n\n        self._settings = get_settings()\n        self._settings.events.changed.connect(self._update_key)\n\n    def _update_key(self, event: Event):\n        self.changed.emit({f\'{self._PREFIX}{event.key}\'})\n\n    def __del__(self):\n        self._settings.events.changed.disconnect(self._update_key)\n\n    def __missing__(self, key: str) -> Any:\n        if key.startswith(self._PREFIX):\n            splits = [k for k in key.split(\'.\')[1:] if k]\n            val: Any = self._settings\n            if splits:\n                while splits:\n                    val = getattr(val, splits.pop(0))\n                if hasattr(val, \'dict\'):\n                    val = val.dict()\n                return val\n        return super().__missing__(key)\n\n    def new_child(self, m: Optional[dict] = None) -> Context:  # type: ignore\n        """New ChainMap with a new map followed by all previous maps.\n\n        If no map is provided, an empty dict is used.\n        """\n        # important to use self, not *self.maps\n        return Context(m or {}, self)  # type: ignore\n\n    def __setitem__(self, k: str, v: Any) -> None:\n        if k.startswith(self._PREFIX):\n            raise ValueError(\n                trans._(\n                    \'Cannot set key starting with {prefix!r}\',\n                    deferred=True,\n                    prefix=self._PREFIX,\n                )\n            )\n\n        return super().__setitem__(k, v)\n\n    def __bool__(self):\n        # settings mappings are always populated, so we can always return True\n        return True\n\n\ndef create_context(\n    obj: object,\n    max_depth: int = 20,\n    start: int = 2,\n    root: Optional[Context] = None,\n) -> Context:\n    return _create_context(\n        obj=obj,\n        max_depth=max_depth,\n        start=start,\n        root=root,\n        root_class=SettingsAwareContext,\n    )\n',
            'napari/_app_model/context/_layerlist_context.py': 'from __future__ import annotations\n\nimport contextlib\nfrom typing import TYPE_CHECKING, Optional, Union\n\nfrom app_model.expressions import ContextKey\n\nfrom napari._app_model.context._context_keys import ContextNamespace\nfrom napari.utils._dtype import normalize_dtype\nfrom napari.utils.translations import trans\n\nif TYPE_CHECKING:\n    from numpy.typing import DTypeLike\n\n    from napari.components.layerlist import LayerList\n    from napari.layers import Layer\n    from napari.utils.events import Selection\n\n    LayerSel = Selection[Layer]\n\n\ndef _len(layers: Union[LayerSel, LayerList]) -> int:\n    return len(layers)\n\n\nclass LayerListContextKeys(ContextNamespace[\'Layer\']):\n    """These are the available context keys relating to a LayerList.\n\n    Consists of a default value, a description, and a function to retrieve the\n    current value from `layers`.\n    """\n\n    num_layers = ContextKey(\n        0,\n        trans._(\'Number of layers.\'),\n        _len,\n    )\n\n\ndef _all_linked(s: LayerSel) -> bool:\n    from napari.layers.utils._link_layers import layer_is_linked\n\n    return bool(s and all(layer_is_linked(x) for x in s))\n\n\ndef _n_unselected_links(s: LayerSel) -> int:\n    from napari.layers.utils._link_layers import get_linked_layers\n\n    return len(get_linked_layers(*s) - s)\n\n\ndef _is_rgb(s: LayerSel) -> bool:\n    return getattr(s.active, \'rgb\', False)\n\n\ndef _only_img(s: LayerSel) -> bool:\n    return bool(s and all(x._type_string == \'image\' for x in s))\n\n\ndef _n_selected_imgs(s: LayerSel) -> int:\n    return sum(x._type_string == \'image\' for x in s)\n\n\ndef _only_labels(s: LayerSel) -> bool:\n    return bool(s and all(x._type_string == \'labels\' for x in s))\n\n\ndef _n_selected_labels(s: LayerSel) -> int:\n    return sum(x._type_string == \'labels\' for x in s)\n\n\ndef _only_points(s: LayerSel) -> bool:\n    return bool(s and all(x._type_string == \'points\' for x in s))\n\n\ndef _n_selected_points(s: LayerSel) -> int:\n    return sum(x._type_string == \'points\' for x in s)\n\n\ndef _only_shapes(s: LayerSel) -> bool:\n    return bool(s and all(x._type_string == \'shapes\' for x in s))\n\n\ndef _n_selected_shapes(s: LayerSel) -> int:\n    return sum(x._type_string == \'shapes\' for x in s)\n\n\ndef _only_surface(s: LayerSel) -> bool:\n    return bool(s and all(x._type_string == \'surface\' for x in s))\n\n\ndef _n_selected_surfaces(s: LayerSel) -> int:\n    return sum(x._type_string == \'surface\' for x in s)\n\n\ndef _only_vectors(s: LayerSel) -> bool:\n    return bool(s and all(x._type_string == \'vectors\' for x in s))\n\n\ndef _n_selected_vectors(s: LayerSel) -> int:\n    return sum(x._type_string == \'vectors\' for x in s)\n\n\ndef _only_tracks(s: LayerSel) -> bool:\n    return bool(s and all(x._type_string == \'tracks\' for x in s))\n\n\ndef _n_selected_tracks(s: LayerSel) -> int:\n    return sum(x._type_string == \'tracks\' for x in s)\n\n\ndef _active_type(s: LayerSel) -> Optional[str]:\n    return s.active._type_string if s.active else None\n\n\ndef _active_ndim(s: LayerSel) -> Optional[int]:\n    return getattr(s.active.data, \'ndim\', None) if s.active else None\n\n\ndef _active_shape(s: LayerSel) -> Optional[tuple[int, ...]]:\n    return getattr(s.active.data, \'shape\', None) if s.active else None\n\n\ndef _same_shape(s: LayerSel) -> bool:\n    """Return true when all given layers have the same shape.\n\n    Notes\n    -----\n    The cast to tuple() is needed because some array libraries, specifically\n    Apple\'s mlx [1]_, return a list, which is not hashable and thus causes the\n    set (``{}``) to fail.\n\n    The Data APIs Array spec specifies that ``.shape`` should be a tuple, or,\n    if a custom type, it should be an immutable type [2]_, so in time, the cast\n    to tuple could be removed, once all major libraries support the spec.\n\n    References\n    ----------\n    .. [1] https://github.com/ml-explore/mlx\n    .. [2] https://data-apis.org/array-api/latest/API_specification/generated/array_api.array.shape.html\n    """\n    return len({tuple(getattr(x.data, \'shape\', ())) for x in s}) == 1\n\n\ndef _active_dtype(s: LayerSel) -> DTypeLike:\n    dtype = None\n    if s.active:\n        with contextlib.suppress(AttributeError):\n            dtype = normalize_dtype(s.active.data.dtype).__name__\n    return dtype\n\n\ndef _same_type(s: LayerSel) -> bool:\n    return len({x._type_string for x in s}) == 1\n\n\ndef _active_is_image_3d(s: LayerSel) -> bool:\n    _activ_ndim = _active_ndim(s)\n    return (\n        _active_type(s) == \'image\'\n        and _activ_ndim is not None\n        and (_activ_ndim > 3 or (_activ_ndim) > 2 and not _is_rgb(s))\n    )\n\n\ndef _empty_shapes_layer_selected(s: LayerSel) -> bool:\n    return any(x._type_string == \'shapes\' and not len(x.data) for x in s)\n\n\nclass LayerListSelectionContextKeys(ContextNamespace[\'LayerSel\']):\n    """Available context keys relating to the selection in a LayerList.\n\n    Consists of a default value, a description, and a function to retrieve the\n    current value from `layers.selection`.\n    """\n\n    num_selected_layers = ContextKey(\n        0,\n        trans._(\'Number of currently selected layers.\'),\n        _len,\n    )\n    num_selected_layers_linked = ContextKey(\n        False,\n        trans._(\'True when all selected layers are linked.\'),\n        _all_linked,\n    )\n    num_unselected_linked_layers = ContextKey(\n        0,\n        trans._(\'Number of unselected layers linked to selected layer(s).\'),\n        _n_unselected_links,\n    )\n    active_layer_is_rgb = ContextKey(\n        False,\n        trans._(\'True when the active layer is RGB.\'),\n        _is_rgb,\n    )\n    active_layer_type = ContextKey[\'LayerSel\', Optional[str]](\n        None,\n        trans._(\n            \'Lowercase name of active layer type, or None of none active.\'\n        ),\n        _active_type,\n    )\n    # TODO: try to reduce these `num_selected_x_layers` to a single set of strings\n    # or something... however, this would require that our context expressions\n    # support Sets, tuples, lists, etc...  which they currently do not.\n    num_selected_image_layers = ContextKey(\n        0,\n        trans._(\'Number of selected image layers.\'),\n        _n_selected_imgs,\n    )\n    num_selected_labels_layers = ContextKey(\n        0,\n        trans._(\'Number of selected labels layers.\'),\n        _n_selected_labels,\n    )\n    num_selected_points_layers = ContextKey(\n        0,\n        trans._(\'Number of selected points layers.\'),\n        _n_selected_points,\n    )\n    num_selected_shapes_layers = ContextKey(\n        0,\n        trans._(\'Number of selected shapes layers.\'),\n        _n_selected_shapes,\n    )\n    num_selected_surface_layers = ContextKey(\n        0,\n        trans._(\'Number of selected surface layers.\'),\n        _n_selected_surfaces,\n    )\n    num_selected_vectors_layers = ContextKey(\n        0,\n        trans._(\'Number of selected vectors layers.\'),\n        _n_selected_vectors,\n    )\n    num_selected_tracks_layers = ContextKey(\n        0,\n        trans._(\'Number of selected tracks layers.\'),\n        _n_selected_tracks,\n    )\n    active_layer_ndim = ContextKey[\'LayerSel\', Optional[int]](\n        None,\n        trans._(\n            \'Number of dimensions in the active layer, or `None` if nothing is active.\'\n        ),\n        _active_ndim,\n    )\n    active_layer_shape = ContextKey[\'LayerSel\', Optional[tuple[int, ...]]](\n        (),\n        trans._(\'Shape of the active layer, or `None` if nothing is active.\'),\n        _active_shape,\n    )\n    active_layer_is_image_3d = ContextKey(\n        False,\n        trans._(\'True when the active layer is a 3D image.\'),\n        _active_is_image_3d,\n    )\n    active_layer_dtype = ContextKey(\n        None,\n        trans._(\'Dtype of the active layer, or `None` if nothing is active.\'),\n        _active_dtype,\n    )\n    all_selected_layers_same_shape = ContextKey(\n        False,\n        trans._(\'True when all selected layers have the same shape.\'),\n        _same_shape,\n    )\n    all_selected_layers_same_type = ContextKey(\n        False,\n        trans._(\'True when all selected layers are of the same type.\'),\n        _same_type,\n    )\n    all_selected_layers_labels = ContextKey(\n        False,\n        trans._(\'True when all selected layers are labels.\'),\n        _only_labels,\n    )\n    selected_empty_shapes_layer = ContextKey(\n        False,\n        trans._(\'True when there is a shapes layer without data selected.\'),\n        _empty_shapes_layer_selected,\n    )\n',
            'napari/_qt/containers/_layer_delegate.py': '"""\nGeneral rendering flow:\n\n1. The List/Tree view needs to display or edit an index in the model...\n2. It gets the ``itemDelegate``\n    a. A custom delegate can be set with ``setItemDelegate``\n    b. ``QStyledItemDelegate`` is the default delegate for all Qt item views,\n       and is installed upon them when they are created.\n3. ``itemDelegate.paint`` is called on the index being displayed\n4. Each index in the model has various data elements (i.e. name, image, etc..),\n   each of which has a "data role".  A model should return the appropriate data\n   for each role by reimplementing ``QAbstractItemModel.data``.\n    a. `QStyledItemDelegate` implements display and editing for the most common\n       datatypes expected by users, including booleans, integers, and strings.\n    b. If the delegate does not support painting of the data types you need or\n       you want to customize the drawing of items, you need to subclass\n       ``QStyledItemDelegate``, and reimplement ``paint()`` and possibly\n       ``sizeHint()``.\n    c. When reimplementing ``paint()``, one typically handles the datatypes\n       they would like to draw and uses the superclass implementation for other\n       types.\n5. The default implementation of ``QStyledItemDelegate.paint`` paints the item\n   using the view\'s ``QStyle`` (which is, by default, an OS specific style...\n   but see ``QCommonStyle`` for a generic implementation)\n    a. It is also possible to override the view\'s style, using either a\n    subclass of ``QCommonStyle``, for a platform-independent look and feel, or\n    ``QProxyStyle``, which let\'s you override only certain stylistic elements\n    on any platform, falling back to the system default otherwise.\n    b. ``QStyle`` paints various elements using methods like ``drawPrimitive``\n       and ``drawControl``.  These can be overridden for very fine control.\n6. It is hard to use stylesheets with custom ``QStyles``... but it\'s possible\n   to style sub-controls in ``QAbstractItemView`` (such as ``QTreeView``):\n   https://doc.qt.io/qt-5/stylesheet-reference.html#list-of-sub-controls\n\n"""\n\nfrom __future__ import annotations\n\nfrom typing import TYPE_CHECKING\nfrom weakref import WeakKeyDictionary, ref\n\nfrom qtpy.QtCore import QPoint, QSize, Qt, Signal\nfrom qtpy.QtGui import QMouseEvent, QMovie, QPixmap\nfrom qtpy.QtWidgets import QStyledItemDelegate\n\nfrom napari._app_model.constants import MenuId\nfrom napari._app_model.context import get_context\nfrom napari._qt._qapp_model import build_qmodel_menu\nfrom napari._qt._qapp_model.qactions._layerlist_context import (\n    is_valid_spatial_in_clipboard,\n)\nfrom napari._qt.containers._base_item_model import ItemRole\nfrom napari._qt.containers.qt_layer_model import LoadedRole, ThumbnailRole\nfrom napari._qt.qt_resources import QColoredSVGIcon\nfrom napari.resources import LOADING_GIF_PATH\n\nif TYPE_CHECKING:\n    from qtpy import QtCore\n    from qtpy.QtGui import QPainter\n    from qtpy.QtWidgets import QStyleOptionViewItem, QWidget\n\n    from napari.components.layerlist import LayerList\n\n\nclass LayerDelegate(QStyledItemDelegate):\n    """A QItemDelegate specialized for painting Layer objects.\n\n    In Qt\'s `Model/View architecture\n    <https://doc.qt.io/qt-5/model-view-programming.html>`_. A *delegate* is an\n    object that controls the visual rendering (and editing widgets) of an item\n    in a view. For more, see:\n    https://doc.qt.io/qt-5/model-view-programming.html#delegate-classes\n\n    This class provides the logic required to paint a Layer item in the\n    :class:`napari._qt.containers.QtLayerList`.  The `QStyledItemDelegate`\n    super-class provides most of the logic (including display/editing of the\n    layer name, a visibility checkbox, and an icon for the layer type).  This\n    subclass provides additional logic for drawing the layer thumbnail, picking\n    the appropriate icon for the layer, and some additional style/UX issues.\n    """\n\n    loading_frame_changed = Signal()\n\n    def __init__(self, parent=None):\n        super().__init__(parent)\n        self._load_movie = QMovie(LOADING_GIF_PATH)\n        self._load_movie.setScaledSize(QSize(18, 18))\n        self._load_movie.frameChanged.connect(self.loading_frame_changed)\n        self._layer_visibility_states = WeakKeyDictionary()\n        self._alt_click_layer = lambda: None\n\n    def paint(\n        self,\n        painter: QPainter,\n        option: QStyleOptionViewItem,\n        index: QtCore.QModelIndex,\n    ):\n        """Paint the item in the model at `index`."""\n        # update the icon based on layer type\n\n        self.get_layer_icon(option, index)\n        # paint the standard itemView (includes name, icon, and vis. checkbox)\n        super().paint(painter, option, index)\n        # paint loading indicator if needed\n        self._paint_loading(painter, option, index)\n        # paint the thumbnail\n        self._paint_thumbnail(painter, option, index)\n\n    def get_layer_icon(\n        self, option: QStyleOptionViewItem, index: QtCore.QModelIndex\n    ):\n        """Add the appropriate QIcon to the item based on the layer type."""\n        layer = index.data(ItemRole)\n        if layer is None:\n            return\n        if hasattr(layer, \'is_group\') and layer.is_group():  # for layer trees\n            expanded = option.widget.isExpanded(index)\n            icon_name = \'folder-open\' if expanded else \'folder\'\n        else:\n            icon_name = f\'new_{layer._type_string}\'\n\n        try:\n            icon = QColoredSVGIcon.from_resources(icon_name)\n        except ValueError:\n            return\n        # guessing theme rather than passing it through.\n        bg = option.palette.color(option.palette.ColorRole.Window).red()\n        option.icon = icon.colored(theme=\'dark\' if bg < 128 else \'light\')\n        option.decorationSize = QSize(18, 18)\n        option.decorationPosition = (\n            option.Position.Right\n        )  # put icon on the right\n        option.features |= option.ViewItemFeature.HasDecoration\n\n    def _paint_loading(\n        self,\n        painter: QPainter,\n        option: QStyleOptionViewItem,\n        index: QtCore.QModelIndex,\n    ):\n        """Paint loading layer indicator."""\n        loaded = index.data(LoadedRole)\n        if not loaded:\n            self._load_movie.start()\n            load_rect = option.rect.translated(4, 8)\n            h = index.data(Qt.ItemDataRole.SizeHintRole).height() - 16\n            load_rect.setWidth(h)\n            load_rect.setHeight(h)\n            painter.drawPixmap(load_rect, self._load_movie.currentPixmap())\n\n    def _paint_thumbnail(self, painter, option, index):\n        """paint the layer thumbnail."""\n        # paint the thumbnail\n        # MAGICNUMBER: numbers from the margin applied in the stylesheet to\n        # QtLayerTreeView::item\n        loaded = index.data(LoadedRole)\n        if loaded:\n            # only pause the loading movie if all the layers are loaded. The\n            # last layer that enters the loaded state will pause the load\n            # movie. This is needed since there is only one instance of the\n            # delegate and therefore only one instance of the load movie shared\n            # between all the layer items.\n            all_loaded = index.model().sourceModel().all_loaded()\n            if all_loaded:\n                self._load_movie.setPaused(True)\n\n            thumb_rect = option.rect.translated(-2, 2)\n            h = index.data(Qt.ItemDataRole.SizeHintRole).height() - 4\n            thumb_rect.setWidth(h)\n            thumb_rect.setHeight(h)\n            image = index.data(ThumbnailRole)\n            painter.drawPixmap(thumb_rect, QPixmap.fromImage(image))\n\n    def createEditor(\n        self,\n        parent: QWidget,\n        option: QStyleOptionViewItem,\n        index: QtCore.QModelIndex,\n    ) -> QWidget:\n        """User has double clicked on layer name."""\n        # necessary for geometry, otherwise editor takes up full width.\n        self.get_layer_icon(option, index)\n        editor = super().createEditor(parent, option, index)\n        # make sure editor has same alignment as the display name\n        editor.setAlignment(\n            Qt.AlignmentFlag(index.data(Qt.ItemDataRole.TextAlignmentRole))\n        )\n        return editor\n\n    def editorEvent(\n        self,\n        event: QtCore.QEvent,\n        model: QtCore.QAbstractItemModel,\n        option: QStyleOptionViewItem,\n        index: QtCore.QModelIndex,\n    ) -> bool:\n        """Called when an event has occured in the editor.\n\n        This can be used to customize how the delegate handles mouse/key events\n        """\n        if (\n            event.type() == QMouseEvent.MouseButtonRelease\n            and event.button() == Qt.MouseButton.RightButton\n        ):\n            pnt = (\n                event.globalPosition().toPoint()\n                if hasattr(event, \'globalPosition\')\n                else event.globalPos()\n            )\n\n            self.show_context_menu(index, model, pnt, option.widget)\n\n        # if the user clicks quickly on the visibility checkbox, we *don\'t*\n        # want it to be interpreted as a double-click.  We want the visibilty\n        # to simply be toggled.\n        if event.type() == QMouseEvent.MouseButtonDblClick:\n            self.initStyleOption(option, index)\n            style = option.widget.style()\n            check_rect = style.subElementRect(\n                style.SubElement.SE_ItemViewItemCheckIndicator,\n                option,\n                option.widget,\n            )\n            if check_rect.contains(event.pos()):\n                cur_state = index.data(Qt.ItemDataRole.CheckStateRole)\n                if model.flags(index) & Qt.ItemFlag.ItemIsUserTristate:\n                    state = Qt.CheckState((cur_state + 1) % 3)\n                else:\n                    state = (\n                        Qt.CheckState.Unchecked\n                        if cur_state\n                        else Qt.CheckState.Checked\n                    )\n                return model.setData(\n                    index, state, Qt.ItemDataRole.CheckStateRole\n                )\n\n        # catch alt-click on the vis checkbox and hide *other* layer visibility\n        # on second alt-click, restore the visibility state of the layers\n        if event.type() == QMouseEvent.MouseButtonRelease and (\n            event.button() == Qt.MouseButton.LeftButton\n            and event.modifiers() == Qt.AltModifier\n        ):\n            self.initStyleOption(option, index)\n            style = option.widget.style()\n            check_rect = style.subElementRect(\n                style.SubElement.SE_ItemViewItemCheckIndicator,\n                option,\n                option.widget,\n            )\n            if check_rect.contains(event.pos()):\n                return self._show_on_alt_click_hide_others(model, index)\n\n        # on regular click of visibility icon, clear alt-click state\n        if event.type() == QMouseEvent.MouseButtonRelease and (\n            event.button() == Qt.MouseButton.LeftButton\n        ):\n            self.initStyleOption(option, index)\n            style = option.widget.style()\n            check_rect = style.subElementRect(\n                style.SubElement.SE_ItemViewItemCheckIndicator,\n                option,\n                option.widget,\n            )\n            if check_rect.contains(event.pos()):\n                self._alt_click_layer = lambda: None\n\n        # refer all other events to the QStyledItemDelegate\n        return super().editorEvent(event, model, option, index)\n\n    def _show_on_alt_click_hide_others(\n        self,\n        model: QtCore.QAbstractItemModel,\n        index: QtCore.QModelIndex,\n    ) -> QtCore.QAbstractItemModel:\n        """On alt/option click of a layer show the layer, hide other layers,\n        to be restored once a layer is alt/option-clicked a second time.\n        """\n        alt_clicked_layer = index.data(ItemRole)\n        layer_list: LayerList = model.sourceModel()._root\n        # show the alt-clicked layer\n        state = Qt.CheckState.Checked\n        if self._alt_click_layer() is None:\n            # first click on visibility, so store visibility & hide others\n            for layer in layer_list:\n                self._layer_visibility_states[layer] = layer.visible\n                layer.visible = layer == alt_clicked_layer  # hide others\n            # make a note that this layer was alt-clicked\n            self._alt_click_layer = ref(alt_clicked_layer)\n        elif self._alt_click_layer() is alt_clicked_layer:\n            # second alt-click on same layer, so restore visibility\n            # account for any added/deleted layers when restoring\n            for layer in layer_list:\n                if layer in self._layer_visibility_states:\n                    layer.visible = self._layer_visibility_states[layer]\n            # restore clicked layer to original state\n            if not alt_clicked_layer.visible:\n                state = Qt.CheckState.Unchecked\n            # reset alt-click state\n            self._alt_click_layer = lambda: None\n        else:\n            # option-click on a different layer, hide others, show it\n            for layer in layer_list:\n                layer.visible = layer is alt_clicked_layer\n            # make a note that this layer was alt-clicked\n            self._alt_click_layer = ref(alt_clicked_layer)\n\n        return model.setData(index, state, Qt.ItemDataRole.CheckStateRole)\n\n    def show_context_menu(self, index, model, pos: QPoint, parent):\n        """Show the layerlist context menu.\n        To add a new item to the menu, update the _LAYER_ACTIONS dict.\n        """\n        if not hasattr(self, \'_context_menu\'):\n            self._context_menu = build_qmodel_menu(\n                MenuId.LAYERLIST_CONTEXT, parent=parent\n            )\n\n        layer_list: LayerList = model.sourceModel()._root\n        # update context keys of selected layers\n        for key, get in layer_list._selection_ctx_keys._getters.items():\n            setattr(\n                layer_list._selection_ctx_keys, key, get(layer_list.selection)\n            )\n        ctx = get_context(layer_list)\n        ctx[\'valid_spatial_json_clipboard\'] = is_valid_spatial_in_clipboard()\n        self._context_menu.update_from_context(ctx)\n        self._context_menu.exec_(pos)\n',
            'napari/_qt/containers/_tests/test_qt_layer_list.py': "import numpy as np\nfrom qtpy.QtCore import QModelIndex, QPoint, Qt\nfrom qtpy.QtWidgets import QLineEdit, QStyleOptionViewItem\n\nfrom napari._qt.containers import QtLayerList\nfrom napari._qt.containers._layer_delegate import LayerDelegate\nfrom napari.components import LayerList\nfrom napari.layers import Image, Shapes\n\n\ndef test_set_layer_invisible_makes_item_unchecked(qtbot):\n    view, image = make_qt_layer_list_with_layer(qtbot)\n    assert image.visible\n    assert check_state_at_layer_index(view, 0) == Qt.CheckState.Checked\n\n    image.visible = False\n\n    assert check_state_at_layer_index(view, 0) == Qt.CheckState.Unchecked\n\n\ndef test_set_item_unchecked_makes_layer_invisible(qtbot):\n    view, image = make_qt_layer_list_with_layer(qtbot)\n    assert check_state_at_layer_index(view, 0) == Qt.CheckState.Checked\n    assert image.visible\n\n    view.model().setData(\n        layer_to_model_index(view, 0),\n        Qt.CheckState.Unchecked,\n        Qt.ItemDataRole.CheckStateRole,\n    )\n\n    assert not image.visible\n\n\ndef test_alt_click_to_show_single_layer(qtbot):\n    (\n        image1,\n        image2,\n        image3,\n        layers,\n        view,\n        delegate,\n    ) = make_qt_layer_list_with_delegate(qtbot)\n\n    # hide the middle-layer, image2 and ensure it's unchecked\n    image2.visible = False\n    assert check_state_at_layer_index(view, 1) == Qt.CheckState.Unchecked\n\n    # ensure the other layers are visible & checked\n    assert image3.visible\n    assert check_state_at_layer_index(view, 0) == Qt.CheckState.Checked\n    assert image1.visible\n    assert check_state_at_layer_index(view, 2) == Qt.CheckState.Checked\n\n    # alt-click state should be None\n    assert delegate._alt_click_layer() is None\n\n    # mock an alt-click on bottom-most layer, image1\n    index = layer_to_model_index(view, 2)\n    delegate._show_on_alt_click_hide_others(view.model(), index)\n\n    # alt-click state should be set to image1\n    assert delegate._alt_click_layer() == image1\n\n    # only image1 should be shown, while image3, image2 be hidden\n    assert not image3.visible\n    assert check_state_at_layer_index(view, 0) == Qt.CheckState.Unchecked\n    assert not image2.visible\n    assert check_state_at_layer_index(view, 1) == Qt.CheckState.Unchecked\n    assert image1.visible\n    assert check_state_at_layer_index(view, 2) == Qt.CheckState.Checked\n\n\ndef test_second_alt_click_to_show_different_layer(qtbot):\n    (\n        image1,\n        image2,\n        image3,\n        layers,\n        view,\n        delegate,\n    ) = make_qt_layer_list_with_delegate(qtbot)\n\n    # mock an alt-click on bottom-most layer, image1\n    index = layer_to_model_index(view, 2)\n    delegate._show_on_alt_click_hide_others(view.model(), index)\n\n    # alt-click state should be set to image1\n    assert delegate._alt_click_layer() == image1\n\n    # image2 should be hidden\n    assert not image2.visible\n    assert check_state_at_layer_index(view, 1) == Qt.CheckState.Unchecked\n\n    # mock an alt-click on middle layer, image2\n    index2 = layer_to_model_index(view, 1)\n    delegate._show_on_alt_click_hide_others(view.model(), index2)\n\n    # alt-click state should be set to image2\n    assert delegate._alt_click_layer() == image2\n\n    # only image2 should be shown, while image3, image1 be hidden\n    assert not image3.visible\n    assert check_state_at_layer_index(view, 0) == Qt.CheckState.Unchecked\n    assert not image1.visible\n    assert check_state_at_layer_index(view, 2) == Qt.CheckState.Unchecked\n    assert image2.visible\n    assert check_state_at_layer_index(view, 1) == Qt.CheckState.Checked\n\n\ndef test_second_alt_click_to_restore_layer_state(qtbot):\n    (\n        image1,\n        image2,\n        image3,\n        layers,\n        view,\n        delegate,\n    ) = make_qt_layer_list_with_delegate(qtbot)\n\n    # mock an alt-click on bottom-most layer, image1\n    index = layer_to_model_index(view, 2)\n    delegate._show_on_alt_click_hide_others(view.model(), index)\n\n    # add a layer (will be at position 0)\n    image4 = Image(np.zeros((4, 3)))\n    layers.append(image4)\n    assert image4.visible\n\n    # remove a layer (image3, which has been pushed down to position 1\n    layers.pop(1)\n\n    # mock second alt-click on image1, which should restore initial state\n    delegate._show_on_alt_click_hide_others(view.model(), index)\n\n    # image4 should remain visible (not part of initial state)\n    # image2 should be not visible--that was the initial state\n    assert image4.visible\n    assert image1.visible\n    assert not image2.visible\n\n    # alt-click state should be cleared\n    assert delegate._alt_click_layer() is None\n\n\ndef test_contextual_menu_updates_selection_ctx_keys(monkeypatch, qtbot):\n    shapes_layer = Shapes()\n    layer_list = LayerList()\n    layer_list._create_contexts()\n    layer_list.append(shapes_layer)\n    view = QtLayerList(layer_list)\n    qtbot.addWidget(view)\n    delegate = view.itemDelegate()\n    assert not layer_list[0].data\n\n    layer_list.selection.add(shapes_layer)\n    index = layer_to_model_index(view, 0)\n    assert layer_list._selection_ctx_keys.num_selected_shapes_layers == 1\n    assert layer_list._selection_ctx_keys.selected_empty_shapes_layer\n\n    monkeypatch.setattr(\n        'app_model.backends.qt.QModelMenu.exec_', lambda self, x: x\n    )\n\n    delegate.show_context_menu(\n        index, view.model(), QPoint(10, 10), parent=view\n    )\n    assert layer_list._selection_ctx_keys.selected_empty_shapes_layer\n\n    layer_list[0].add(np.array(([0, 0], [0, 10], [10, 10], [10, 0])))\n    assert layer_list[0].data\n    delegate.show_context_menu(\n        index, view.model(), QPoint(10, 10), parent=view\n    )\n    assert not layer_list._selection_ctx_keys.selected_empty_shapes_layer\n\n\ndef make_qt_layer_list_with_delegate(qtbot):\n    image1 = Image(np.zeros((4, 3)))\n    image2 = Image(np.zeros((4, 3)))\n    image3 = Image(np.zeros((4, 3)))\n\n    layers = LayerList([image1, image2, image3])\n    # this will make the list have image2 on top of image1\n    view = QtLayerList(layers)\n    qtbot.addWidget(view)\n\n    delegate = LayerDelegate()\n    return image1, image2, image3, layers, view, delegate\n\n\ndef make_qt_layer_list_with_layer(qtbot) -> tuple[QtLayerList, Image]:\n    image = Image(np.zeros((4, 3)))\n    layers = LayerList([image])\n    view = QtLayerList(layers)\n    qtbot.addWidget(view)\n    return view, image\n\n\ndef layer_to_model_index(view: QtLayerList, layer_index: int) -> QModelIndex:\n    return view.model().index(layer_index, 0, view.rootIndex())\n\n\ndef check_state_at_layer_index(\n    view: QtLayerList, layer_index: int\n) -> Qt.CheckState:\n    model_index = layer_to_model_index(view, layer_index)\n    value = view.model().data(model_index, Qt.ItemDataRole.CheckStateRole)\n    # The data method returns integer value of the enum in some cases, so\n    # ensure it has the enum type for more explicit assertions.\n    return Qt.CheckState(value)\n\n\ndef test_createEditor(qtbot):\n    view, image = make_qt_layer_list_with_layer(qtbot)\n    model_index = layer_to_model_index(view, 0)\n    delegate = view.itemDelegate()\n    editor = delegate.createEditor(view, QStyleOptionViewItem(), model_index)\n    assert isinstance(editor, QLineEdit)\n    delegate.setEditorData(editor, model_index)\n    assert editor.text() == image.name\n",
            'napari/_qt/containers/qt_layer_list.py': 'from __future__ import annotations\n\nfrom typing import TYPE_CHECKING\n\nfrom qtpy.QtCore import QSortFilterProxyModel, Qt  # type: ignore[attr-defined]\n\nfrom napari._qt.containers._base_item_model import (\n    SortRole,\n    _BaseEventedItemModel,\n)\nfrom napari._qt.containers._layer_delegate import LayerDelegate\nfrom napari._qt.containers.qt_list_view import QtListView\nfrom napari.layers import Layer\nfrom napari.utils.translations import trans\n\nif TYPE_CHECKING:\n    from typing import Optional\n\n    from qtpy.QtGui import QKeyEvent  # type: ignore[attr-defined]\n    from qtpy.QtWidgets import QWidget  # type: ignore[attr-defined]\n\n    from napari.components.layerlist import LayerList\n\n\nclass ReverseProxyModel(QSortFilterProxyModel):\n    """Proxy Model that reverses the view order of a _BaseEventedItemModel."""\n\n    def __init__(self, model: _BaseEventedItemModel) -> None:\n        super().__init__()\n        self.setSourceModel(model)\n        self.setSortRole(SortRole)\n        self.sort(0, Qt.SortOrder.DescendingOrder)\n\n    def dropMimeData(self, data, action, destRow, col, parent):\n        """Handle destination row for dropping with reversed indices."""\n        row = 0 if destRow == -1 else self.sourceModel().rowCount() - destRow\n        return self.sourceModel().dropMimeData(data, action, row, col, parent)\n\n\nclass QtLayerList(QtListView[Layer]):\n    """QItemView subclass specialized for the LayerList.\n\n    This is as mostly for targetting with QSS, applying the delegate and\n    reversing the view with ReverseProxyModel.\n    """\n\n    def __init__(\n        self, root: LayerList, parent: Optional[QWidget] = None\n    ) -> None:\n        super().__init__(root, parent)\n        layer_delegate = LayerDelegate()\n        self.setItemDelegate(layer_delegate)\n        # To be able to update the loading indicator frame in the item delegate\n        # smoothly and also be able to leave the item painted in a coherent\n        # state (showing the loading indicator or the thumbnail)\n        viewport = self.viewport()\n        assert viewport is not None\n\n        layer_delegate.loading_frame_changed.connect(viewport.update)\n\n        self.setToolTip(trans._(\'Layer list\'))\n\n        # This reverses the order of the items in the view,\n        # so items at the end of the list are at the top.\n        self.setModel(ReverseProxyModel(self.model()))\n\n    def keyPressEvent(self, e: Optional[QKeyEvent]) -> None:\n        """Override Qt event to pass events to the viewer."""\n        if e is None:\n            return\n        # capture arrows with modifiers so they are handled by Viewer keybindings\n        if (e.key() == Qt.Key.Key_Up or e.key() == Qt.Key.Key_Down) and (\n            e.modifiers() & Qt.KeyboardModifier.AltModifier\n            or e.modifiers() & Qt.KeyboardModifier.ControlModifier\n            or e.modifiers() & Qt.KeyboardModifier.MetaModifier\n            or e.modifiers() & Qt.KeyboardModifier.ShiftModifier\n        ):\n            e.ignore()\n        elif e.key() != Qt.Key.Key_Space:\n            super().keyPressEvent(e)\n        if e.key() not in (Qt.Key.Key_Backspace, Qt.Key.Key_Delete):\n            e.ignore()  # pass key events up to viewer\n',
            'napari/_qt/qt_main_window.py': '"""\nCustom Qt widgets that serve as native objects that the public-facing elements\nwrap.\n"""\n\nimport contextlib\nimport inspect\nimport os\nimport sys\nimport time\nimport warnings\nfrom collections.abc import MutableMapping, Sequence\nfrom typing import (\n    TYPE_CHECKING,\n    Any,\n    ClassVar,\n    Literal,\n    Optional,\n    Union,\n    cast,\n)\nfrom weakref import WeakValueDictionary\n\nfrom qtpy.QtCore import (\n    QEvent,\n    QEventLoop,\n    QPoint,\n    QProcess,\n    QRect,\n    QSize,\n    Qt,\n    Slot,\n)\nfrom qtpy.QtGui import QIcon\nfrom qtpy.QtWidgets import (\n    QApplication,\n    QDialog,\n    QDockWidget,\n    QHBoxLayout,\n    QMainWindow,\n    QMenu,\n    QShortcut,\n    QToolTip,\n    QWidget,\n)\nfrom superqt.utils import QSignalThrottler\n\nfrom napari._app_model.constants import MenuId\nfrom napari._app_model.context import create_context, get_context\nfrom napari._qt._qapp_model import build_qmodel_menu\nfrom napari._qt._qapp_model.qactions import init_qactions\nfrom napari._qt._qapp_model.qactions._debug import _is_set_trace_active\nfrom napari._qt._qplugins import (\n    _rebuild_npe1_plugins_menu,\n    _rebuild_npe1_samples_menu,\n)\nfrom napari._qt.dialogs.confirm_close_dialog import ConfirmCloseDialog\nfrom napari._qt.dialogs.preferences_dialog import PreferencesDialog\nfrom napari._qt.dialogs.qt_activity_dialog import QtActivityDialog\nfrom napari._qt.dialogs.qt_notification import NapariQtNotification\nfrom napari._qt.qt_event_loop import (\n    NAPARI_ICON_PATH,\n    get_app,\n    quit_app as quit_app_,\n)\nfrom napari._qt.qt_resources import get_stylesheet\nfrom napari._qt.qt_viewer import QtViewer\nfrom napari._qt.utils import QImg2array, qbytearray_to_str, str_to_qbytearray\nfrom napari._qt.widgets.qt_viewer_dock_widget import (\n    _SHORTCUT_DEPRECATION_STRING,\n    QtViewerDockWidget,\n)\nfrom napari._qt.widgets.qt_viewer_status_bar import ViewerStatusBar\nfrom napari.plugins import (\n    menu_item_template as plugin_menu_item_template,\n    plugin_manager,\n)\nfrom napari.plugins._npe2 import index_npe1_adapters\nfrom napari.settings import get_settings\nfrom napari.utils import perf\nfrom napari.utils._proxies import PublicOnlyProxy\nfrom napari.utils.io import imsave\nfrom napari.utils.misc import (\n    in_ipython,\n    in_jupyter,\n    in_python_repl,\n    running_as_constructor_app,\n)\nfrom napari.utils.notifications import Notification\nfrom napari.utils.theme import _themes, get_system_theme\nfrom napari.utils.translations import trans\n\n_sentinel = object()\n\nif TYPE_CHECKING:\n    from magicgui.widgets import Widget\n    from qtpy.QtGui import QImage\n\n    from napari.viewer import Viewer\n\n\nMenuStr = Literal[\n    \'file_menu\',\n    \'view_menu\',\n    \'layers_menu\',\n    \'plugins_menu\',\n    \'window_menu\',\n    \'help_menu\',\n]\n\n\nclass _QtMainWindow(QMainWindow):\n    # This was added so that someone can patch\n    # `napari._qt.qt_main_window._QtMainWindow._window_icon`\n    # to their desired window icon\n    _window_icon = NAPARI_ICON_PATH\n\n    # To track window instances and facilitate getting the "active" viewer...\n    # We use this instead of QApplication.activeWindow for compatibility with\n    # IPython usage. When you activate IPython, it will appear that there are\n    # *no* active windows, so we want to track the most recently active windows\n    _instances: ClassVar[list[\'_QtMainWindow\']] = []\n\n    # `window` is passed through on construction, so it\'s available to a window\n    # provider for dependency injection\n    # See https://github.com/napari/napari/pull/4826\n    def __init__(\n        self, viewer: \'Viewer\', window: \'Window\', parent=None\n    ) -> None:\n        super().__init__(parent)\n        self._ev = None\n        self._window = window\n        self._qt_viewer = QtViewer(viewer, show_welcome_screen=True)\n        self._quit_app = False\n\n        self.setWindowIcon(QIcon(self._window_icon))\n        self.setAttribute(Qt.WidgetAttribute.WA_DeleteOnClose)\n        center = QWidget(self)\n        center.setLayout(QHBoxLayout())\n        center.layout().addWidget(self._qt_viewer)\n        center.layout().setContentsMargins(4, 0, 4, 0)\n        self.setCentralWidget(center)\n\n        self.setWindowTitle(self._qt_viewer.viewer.title)\n\n        self._maximized_flag = False\n        self._fullscreen_flag = False\n        self._normal_geometry = QRect()\n        self._window_size = None\n        self._window_pos = None\n        self._old_size = None\n        self._positions = []\n        self._toggle_menubar_visibility = False\n\n        self._is_close_dialog = {False: True, True: True}\n        # this ia sa workaround for #5335 issue. The dict is used to not\n        # collide shortcuts for close and close all windows\n\n        act_dlg = QtActivityDialog(self._qt_viewer._welcome_widget)\n        self._qt_viewer._welcome_widget.resized.connect(\n            act_dlg.move_to_bottom_right\n        )\n        act_dlg.hide()\n        self._activity_dialog = act_dlg\n\n        self.setStatusBar(ViewerStatusBar(self))\n\n        # Prevent QLineEdit based widgets to keep focus even when clicks are\n        # done outside the widget. See #1571\n        self.setFocusPolicy(Qt.FocusPolicy.StrongFocus)\n\n        # Ideally this would be in `NapariApplication` but that is outside of Qt\n        self._viewer_context = create_context(self)\n\n        settings = get_settings()\n\n        # TODO:\n        # settings.plugins.defaults.call_order = plugin_manager.call_order()\n\n        # set the values in plugins to match the ones saved in settings\n        if settings.plugins.call_order is not None:\n            plugin_manager.set_call_order(settings.plugins.call_order)\n\n        _QtMainWindow._instances.append(self)\n\n        # since we initialize canvas before the window,\n        # we need to manually connect them again.\n        handle = self.windowHandle()\n        if handle is not None:\n            handle.screenChanged.connect(self._qt_viewer.canvas.screen_changed)\n\n        # this is the line that initializes any Qt-based app-model Actions that\n        # were defined somewhere in the `_qt` module and imported in init_qactions\n        init_qactions()\n\n        self.status_throttler = QSignalThrottler(parent=self)\n        self.status_throttler.setTimeout(50)\n        self._throttle_cursor_to_status_connection(viewer)\n\n    def _throttle_cursor_to_status_connection(self, viewer: \'Viewer\'):\n        # In the GUI we expect lots of changes to the cursor position, so\n        # replace the direct connection with a throttled one.\n        with contextlib.suppress(IndexError):\n            viewer.cursor.events.position.disconnect(\n                viewer._update_status_bar_from_cursor\n            )\n        viewer.cursor.events.position.connect(self.status_throttler.throttle)\n        self.status_throttler.triggered.connect(\n            viewer._update_status_bar_from_cursor\n        )\n\n    def statusBar(self) -> \'ViewerStatusBar\':\n        return super().statusBar()\n\n    @classmethod\n    def current(cls) -> Optional[\'_QtMainWindow\']:\n        return cls._instances[-1] if cls._instances else None\n\n    @classmethod\n    def current_viewer(cls):\n        window = cls.current()\n        return window._qt_viewer.viewer if window else None\n\n    def event(self, e: QEvent) -> bool:\n        if (\n            e.type() == QEvent.Type.ToolTip\n            and self._qt_viewer.viewer.tooltip.visible\n        ):\n            # globalPos is for Qt5 e.globalPosition().toPoint() is for QT6\n            # https://doc-snapshots.qt.io/qt6-dev/qmouseevent-obsolete.html#globalPos\n            pnt = (\n                e.globalPosition().toPoint()\n                if hasattr(e, \'globalPosition\')\n                else e.globalPos()\n            )\n            QToolTip.showText(pnt, self._qt_viewer.viewer.tooltip.text, self)\n        if e.type() in {QEvent.Type.WindowActivate, QEvent.Type.ZOrderChange}:\n            # upon activation or raise_, put window at the end of _instances\n            with contextlib.suppress(ValueError):\n                inst = _QtMainWindow._instances\n                inst.append(inst.pop(inst.index(self)))\n\n        res = super().event(e)\n\n        if e.type() == QEvent.Type.Close and e.isAccepted():\n            # when we close the MainWindow, remove it from the instance list\n            with contextlib.suppress(ValueError):\n                _QtMainWindow._instances.remove(self)\n\n        return res\n\n    def isFullScreen(self):\n        # Needed to prevent errors when going to fullscreen mode on Windows\n        # Use a flag attribute to determine if the window is in full screen mode\n        # See https://bugreports.qt.io/browse/QTBUG-41309\n        # Based on https://github.com/spyder-ide/spyder/pull/7720\n        return self._fullscreen_flag\n\n    def showNormal(self):\n        # Needed to prevent errors when going to fullscreen mode on Windows. Here we:\n        #   * Set fullscreen flag\n        #   * Remove `Qt.FramelessWindowHint` and `Qt.WindowStaysOnTopHint` window flags if needed\n        #   * Set geometry to previously stored normal geometry or default empty QRect\n        # Always call super `showNormal` to set Qt window state\n        # See https://bugreports.qt.io/browse/QTBUG-41309\n        # Based on https://github.com/spyder-ide/spyder/pull/7720\n        self._fullscreen_flag = False\n        if os.name == \'nt\':\n            self.setWindowFlags(\n                self.windowFlags()\n                ^ (\n                    Qt.WindowType.FramelessWindowHint\n                    | Qt.WindowType.WindowStaysOnTopHint\n                )\n            )\n            self.setGeometry(self._normal_geometry)\n        super().showNormal()\n\n    def showFullScreen(self):\n        # Needed to prevent errors when going to fullscreen mode on Windows. Here we:\n        #   * Set fullscreen flag\n        #   * Add `Qt.FramelessWindowHint` and `Qt.WindowStaysOnTopHint` window flags if needed\n        #   * Call super `showNormal` to update the normal screen geometry to apply it later if needed\n        #   * Save window normal geometry if needed\n        #   * Get screen geometry\n        #   * Set geometry window to use total screen geometry +1 in every direction if needed\n        # If the workaround is not needed just call super `showFullScreen`\n        # See https://bugreports.qt.io/browse/QTBUG-41309\n        # Based on https://github.com/spyder-ide/spyder/pull/7720\n        self._fullscreen_flag = True\n        if os.name == \'nt\':\n            self.setWindowFlags(\n                self.windowFlags()\n                | Qt.WindowType.FramelessWindowHint\n                | Qt.WindowType.WindowStaysOnTopHint\n            )\n            super().showNormal()\n            self._normal_geometry = self.normalGeometry()\n            screen_rect = self.windowHandle().screen().geometry()\n            self.setGeometry(\n                screen_rect.left() - 1,\n                screen_rect.top() - 1,\n                screen_rect.width() + 2,\n                screen_rect.height() + 2,\n            )\n        else:\n            super().showFullScreen()\n\n    def eventFilter(self, source, event):\n        # Handle showing hidden menubar on mouse move event.\n        # We do not hide menubar when a menu is being shown or\n        # we are not in menubar toggled state\n        if (\n            QApplication.activePopupWidget() is None\n            and hasattr(self, \'_toggle_menubar_visibility\')\n            and self._toggle_menubar_visibility\n        ):\n            if event.type() == QEvent.Type.MouseMove:\n                if self.menuBar().isHidden():\n                    rect = self.geometry()\n                    # set mouse-sensitive zone to trigger showing the menubar\n                    rect.setHeight(25)\n                    if rect.contains(event.globalPos()):\n                        self.menuBar().show()\n                else:\n                    rect = QRect(\n                        self.menuBar().mapToGlobal(QPoint(0, 0)),\n                        self.menuBar().size(),\n                    )\n                    if not rect.contains(event.globalPos()):\n                        self.menuBar().hide()\n            elif event.type() == QEvent.Type.Leave and source is self:\n                self.menuBar().hide()\n        return super().eventFilter(source, event)\n\n    def _load_window_settings(self):\n        """\n        Load window layout settings from configuration.\n        """\n        settings = get_settings()\n        window_position = settings.application.window_position\n\n        # It\'s necessary to verify if the window/position value is valid with\n        # the current screen.\n        if not window_position:\n            window_position = (self.x(), self.y())\n        else:\n            origin_x, origin_y = window_position\n            screen = QApplication.screenAt(QPoint(origin_x, origin_y))\n            screen_geo = screen.geometry() if screen else None\n            if not screen_geo:\n                window_position = (self.x(), self.y())\n\n        return (\n            settings.application.window_state,\n            settings.application.window_size,\n            window_position,\n            settings.application.window_maximized,\n            settings.application.window_fullscreen,\n        )\n\n    def _get_window_settings(self):\n        """Return current window settings.\n\n        Symmetric to the \'set_window_settings\' setter.\n        """\n\n        window_fullscreen = self.isFullScreen()\n        if window_fullscreen:\n            window_maximized = self._maximized_flag\n        else:\n            window_maximized = self.isMaximized()\n\n        window_state = qbytearray_to_str(self.saveState())\n        return (\n            window_state,\n            self._window_size or (self.width(), self.height()),\n            self._window_pos or (self.x(), self.y()),\n            window_maximized,\n            window_fullscreen,\n        )\n\n    def _set_window_settings(\n        self,\n        window_state,\n        window_size,\n        window_position,\n        window_maximized,\n        window_fullscreen,\n    ):\n        """\n        Set window settings.\n\n        Symmetric to the \'get_window_settings\' accessor.\n        """\n        self.setUpdatesEnabled(False)\n        self.setWindowState(Qt.WindowState.WindowNoState)\n\n        if window_position:\n            window_position = QPoint(*window_position)\n            self.move(window_position)\n\n        if window_size:\n            window_size = QSize(*window_size)\n            self.resize(window_size)\n\n        if window_state:\n            self.restoreState(str_to_qbytearray(window_state))\n\n        # Toggling the console visibility is disabled when it is not\n        # available, so ensure that it is hidden.\n        if in_ipython() or in_jupyter() or in_python_repl():\n            self._qt_viewer.dockConsole.setVisible(False)\n\n        if window_fullscreen:\n            self._maximized_flag = window_maximized\n            self.showFullScreen()\n        elif window_maximized:\n            self.setWindowState(Qt.WindowState.WindowMaximized)\n\n        self.setUpdatesEnabled(True)\n\n    def _save_current_window_settings(self):\n        """Save the current geometry of the main window."""\n        (\n            window_state,\n            window_size,\n            window_position,\n            window_maximized,\n            window_fullscreen,\n        ) = self._get_window_settings()\n\n        settings = get_settings()\n        if settings.application.save_window_geometry:\n            settings.application.window_maximized = window_maximized\n            settings.application.window_fullscreen = window_fullscreen\n            settings.application.window_position = window_position\n            settings.application.window_size = window_size\n            settings.application.window_statusbar = (\n                not self.statusBar().isHidden()\n            )\n\n        if settings.application.save_window_state:\n            settings.application.window_state = window_state\n\n    def close(self, quit_app=False, confirm_need=False):\n        """Override to handle closing app or just the window."""\n        if hasattr(self.status_throttler, \'_timer\'):\n            self.status_throttler._timer.stop()\n        if not quit_app and not self._qt_viewer.viewer.layers:\n            return super().close()\n        confirm_need_local = confirm_need and self._is_close_dialog[quit_app]\n        self._is_close_dialog[quit_app] = False\n        # here we save information that we could request confirmation on close\n        # So fi function `close` is called again, we don\'t ask again but just close\n        if (\n            not confirm_need_local\n            or not get_settings().application.confirm_close_window\n            or ConfirmCloseDialog(self, quit_app).exec_() == QDialog.Accepted\n        ):\n            self._quit_app = quit_app\n            self._is_close_dialog[quit_app] = True\n            # here we inform that confirmation dialog is not open\n            self._qt_viewer.dims.stop()\n            return super().close()\n        self._is_close_dialog[quit_app] = True\n        return None\n        # here we inform that confirmation dialog is not open\n\n    def close_window(self):\n        """Close active dialog or active window."""\n        parent = QApplication.focusWidget()\n        while parent is not None:\n            if isinstance(parent, QMainWindow):\n                self.close()\n                break\n\n            if isinstance(parent, QDialog):\n                parent.close()\n                break\n\n            try:\n                parent = parent.parent()\n            except AttributeError:\n                parent = getattr(parent, \'_parent\', None)\n\n    def show(self, block=False):\n        super().show()\n        self._qt_viewer.setFocus()\n        if block:\n            self._ev = QEventLoop()\n            self._ev.exec()\n\n    def changeEvent(self, event):\n        """Handle window state changes."""\n        if event.type() == QEvent.Type.WindowStateChange:\n            # TODO: handle maximization issue. When double clicking on the\n            # title bar on Mac the resizeEvent is called an varying amount\n            # of times which makes it hard to track the original size before\n            # maximization.\n            condition = (\n                self.isMaximized() if os.name == \'nt\' else self.isFullScreen()\n            )\n            if condition and self._old_size is not None:\n                if self._positions and len(self._positions) > 1:\n                    self._window_pos = self._positions[-2]\n\n                self._window_size = (\n                    self._old_size.width(),\n                    self._old_size.height(),\n                )\n            else:\n                self._old_size = None\n                self._window_pos = None\n                self._window_size = None\n                self._positions = []\n\n        super().changeEvent(event)\n\n    def keyPressEvent(self, event):\n        """Called whenever a key is pressed.\n\n        Parameters\n        ----------\n        event : qtpy.QtCore.QEvent\n            Event from the Qt context.\n        """\n        self._qt_viewer.canvas._scene_canvas._backend._keyEvent(\n            self._qt_viewer.canvas._scene_canvas.events.key_press, event\n        )\n        event.accept()\n\n    def keyReleaseEvent(self, event):\n        """Called whenever a key is released.\n\n        Parameters\n        ----------\n        event : qtpy.QtCore.QEvent\n            Event from the Qt context.\n        """\n        self._qt_viewer.canvas._scene_canvas._backend._keyEvent(\n            self._qt_viewer.canvas._scene_canvas.events.key_release, event\n        )\n        event.accept()\n\n    def resizeEvent(self, event):\n        """Override to handle original size before maximizing."""\n        # the first resize event will have nonsense positions that we don\'t\n        # want to store (and potentially restore)\n        if event.oldSize().isValid():\n            self._old_size = event.oldSize()\n            self._positions.append((self.x(), self.y()))\n\n            if self._positions and len(self._positions) >= 2:\n                self._window_pos = self._positions[-2]\n                self._positions = self._positions[-2:]\n\n        super().resizeEvent(event)\n\n    def closeEvent(self, event):\n        """This method will be called when the main window is closing.\n\n        Regardless of whether cmd Q, cmd W, or the close button is used...\n        """\n        if (\n            event.spontaneous()\n            and get_settings().application.confirm_close_window\n            and self._qt_viewer.viewer.layers\n            and ConfirmCloseDialog(self, False).exec_() != QDialog.Accepted\n        ):\n            event.ignore()\n            return\n\n        if self._ev and self._ev.isRunning():\n            self._ev.quit()\n\n        # Close any floating dockwidgets\n        for dock in self.findChildren(QtViewerDockWidget):\n            if isinstance(dock, QWidget) and dock.isFloating():\n                dock.setFloating(False)\n\n        self._save_current_window_settings()\n\n        # On some versions of Darwin, exiting while fullscreen seems to tickle\n        # some bug deep in NSWindow.  This forces the fullscreen keybinding\n        # test to complete its draw cycle, then pop back out of fullscreen.\n        if self.isFullScreen():\n            self.showNormal()\n            for _ in range(5):\n                time.sleep(0.1)\n                QApplication.processEvents()\n\n        self._qt_viewer.dims.stop()\n\n        if self._quit_app:\n            quit_app_()\n\n        event.accept()\n\n    def restart(self):\n        """Restart the napari application in a detached process."""\n        process = QProcess()\n        process.setProgram(sys.executable)\n\n        if not running_as_constructor_app():\n            process.setArguments(sys.argv)\n\n        process.startDetached()\n        self.close(quit_app=True)\n\n    def toggle_menubar_visibility(self):\n        """\n        Change menubar to be shown or to be hidden and shown on mouse movement.\n\n        For the mouse movement functionality see the `eventFilter` implementation.\n        """\n        self._toggle_menubar_visibility = not self._toggle_menubar_visibility\n        self.menuBar().setVisible(not self._toggle_menubar_visibility)\n        return self._toggle_menubar_visibility\n\n    @staticmethod\n    @Slot(Notification)\n    def show_notification(notification: Notification):\n        """Show notification coming from a thread."""\n        NapariQtNotification.show_notification(notification)\n\n\nclass Window:\n    """Application window that contains the menu bar and viewer.\n\n    Parameters\n    ----------\n    viewer : napari.components.ViewerModel\n        Contained viewer widget.\n\n    Attributes\n    ----------\n    file_menu : qtpy.QtWidgets.QMenu\n        File menu.\n    help_menu : qtpy.QtWidgets.QMenu\n        Help menu.\n    main_menu : qtpy.QtWidgets.QMainWindow.menuBar\n        Main menubar.\n    view_menu : qtpy.QtWidgets.QMenu\n        View menu.\n    window_menu : qtpy.QtWidgets.QMenu\n        Window menu.\n    """\n\n    def __init__(self, viewer: \'Viewer\', *, show: bool = True) -> None:\n        # create QApplication if it doesn\'t already exist\n        qapp = get_app()\n\n        # Dictionary holding dock widgets\n        self._dock_widgets: MutableMapping[str, QtViewerDockWidget] = (\n            WeakValueDictionary()\n        )\n        self._unnamed_dockwidget_count = 1\n\n        self._pref_dialog = None\n\n        # Connect the Viewer and create the Main Window\n        self._qt_window = _QtMainWindow(viewer, self)\n        qapp.installEventFilter(self._qt_window)\n\n        # connect theme events before collecting plugin-provided themes\n        # to ensure icons from the plugins are generated correctly.\n        _themes.events.added.connect(self._add_theme)\n        _themes.events.removed.connect(self._remove_theme)\n\n        # discover any themes provided by plugins\n        plugin_manager.discover_themes()\n        self._setup_existing_themes()\n\n        # import and index all discovered shimmed npe1 plugins\n        index_npe1_adapters()\n\n        self._add_menus()\n        self._update_theme()\n        self._update_theme_font_size()\n        get_settings().appearance.events.theme.connect(self._update_theme)\n        get_settings().appearance.events.font_size.connect(\n            self._update_theme_font_size\n        )\n\n        self._add_viewer_dock_widget(self._qt_viewer.dockConsole, tabify=False)\n        self._add_viewer_dock_widget(\n            self._qt_viewer.dockLayerControls,\n            tabify=False,\n        )\n        self._add_viewer_dock_widget(\n            self._qt_viewer.dockLayerList, tabify=False\n        )\n        if perf.perf_config is not None:\n            self._add_viewer_dock_widget(\n                self._qt_viewer.dockPerformance, menu=self.window_menu\n            )\n\n        viewer.events.help.connect(self._help_changed)\n        viewer.events.title.connect(self._title_changed)\n        viewer.events.theme.connect(self._update_theme)\n        viewer.events.status.connect(self._status_changed)\n\n        if show:\n            self.show()\n            # Ensure the controls dock uses the minimum height\n            self._qt_window.resizeDocks(\n                [\n                    self._qt_viewer.dockLayerControls,\n                    self._qt_viewer.dockLayerList,\n                ],\n                [self._qt_viewer.dockLayerControls.minimumHeight(), 10000],\n                Qt.Orientation.Vertical,\n            )\n\n    def _setup_existing_themes(self, connect: bool = True):\n        """This function is only executed once at the startup of napari\n        to connect events to themes that have not been connected yet.\n\n        Parameters\n        ----------\n        connect : bool\n            Determines whether the `connect` or `disconnect` method should be used.\n        """\n        for theme in _themes.values():\n            if connect:\n                self._connect_theme(theme)\n            else:\n                self._disconnect_theme(theme)\n\n    def _connect_theme(self, theme):\n        # connect events to update theme. Here, we don\'t want to pass the event\n        # since it won\'t have the right `value` attribute.\n        theme.events.background.connect(self._update_theme_no_event)\n        theme.events.foreground.connect(self._update_theme_no_event)\n        theme.events.primary.connect(self._update_theme_no_event)\n        theme.events.secondary.connect(self._update_theme_no_event)\n        theme.events.highlight.connect(self._update_theme_no_event)\n        theme.events.text.connect(self._update_theme_no_event)\n        theme.events.warning.connect(self._update_theme_no_event)\n        theme.events.current.connect(self._update_theme_no_event)\n        theme.events.icon.connect(self._update_theme_no_event)\n        theme.events.font_size.connect(self._update_theme_no_event)\n        theme.events.canvas.connect(\n            lambda _: self._qt_viewer.canvas._set_theme_change(\n                get_settings().appearance.theme\n            )\n        )\n        # connect console-specific attributes only if QtConsole\n        # is present. The `console` is called which might slow\n        # things down a little.\n        if self._qt_viewer._console:\n            theme.events.console.connect(self._qt_viewer.console._update_theme)\n            theme.events.syntax_style.connect(\n                self._qt_viewer.console._update_theme\n            )\n\n    def _disconnect_theme(self, theme):\n        theme.events.background.disconnect(self._update_theme_no_event)\n        theme.events.foreground.disconnect(self._update_theme_no_event)\n        theme.events.primary.disconnect(self._update_theme_no_event)\n        theme.events.secondary.disconnect(self._update_theme_no_event)\n        theme.events.highlight.disconnect(self._update_theme_no_event)\n        theme.events.text.disconnect(self._update_theme_no_event)\n        theme.events.warning.disconnect(self._update_theme_no_event)\n        theme.events.current.disconnect(self._update_theme_no_event)\n        theme.events.icon.disconnect(self._update_theme_no_event)\n        theme.events.font_size.disconnect(self._update_theme_no_event)\n        theme.events.canvas.disconnect(\n            lambda _: self._qt_viewer.canvas._set_theme_change(\n                get_settings().appearance.theme\n            )\n        )\n        # disconnect console-specific attributes only if QtConsole\n        # is present and they were previously connected\n        if self._qt_viewer._console:\n            theme.events.console.disconnect(\n                self._qt_viewer.console._update_theme\n            )\n            theme.events.syntax_style.disconnect(\n                self._qt_viewer.console._update_theme\n            )\n\n    def _add_theme(self, event):\n        """Add new theme and connect events."""\n        theme = event.value\n        self._connect_theme(theme)\n\n    def _remove_theme(self, event):\n        """Remove theme and disconnect events."""\n        theme = event.value\n        self._disconnect_theme(theme)\n\n    @property\n    def qt_viewer(self):\n        warnings.warn(\n            trans._(\n                \'Public access to Window.qt_viewer is deprecated and will be removed in\\n\'\n                \'v0.6.0. It is considered an "implementation detail" of the napari\\napplication, \'\n                \'not part of the napari viewer model. If your use case\\n\'\n                \'requires access to qt_viewer, please open an issue to discuss.\',\n                deferred=True,\n            ),\n            category=FutureWarning,\n            stacklevel=2,\n        )\n        return self._qt_window._qt_viewer\n\n    @property\n    def _qt_viewer(self):\n        # this is starting to be "vestigial"... this property could be removed\n        return self._qt_window._qt_viewer\n\n    @property\n    def _status_bar(self):\n        # TODO: remove from window\n        return self._qt_window.statusBar()\n\n    def _update_menu_state(self, menu: MenuStr):\n        """Update enabled/visible state of menu item with context."""\n        layerlist = self._qt_viewer._layers.model().sourceModel()._root\n        menu_model = getattr(self, menu)\n        menu_model.update_from_context(get_context(layerlist))\n\n    def _update_file_menu_state(self):\n        self._update_menu_state(\'file_menu\')\n\n    def _update_view_menu_state(self):\n        self._update_menu_state(\'view_menu\')\n\n    def _update_layers_menu_state(self):\n        self._update_menu_state(\'layers_menu\')\n\n    def _update_window_menu_state(self):\n        self._update_menu_state(\'window_menu\')\n\n    def _update_plugins_menu_state(self):\n        self._update_menu_state(\'plugins_menu\')\n\n    def _update_help_menu_state(self):\n        self._update_menu_state(\'help_menu\')\n\n    def _update_debug_menu_state(self):\n        viewer_ctx = get_context(self._qt_window)\n        viewer_ctx[\'is_set_trace_active\'] = _is_set_trace_active()\n        self._debug_menu.update_from_context(viewer_ctx)\n\n    # TODO: Remove once npe1 deprecated\n    def _setup_npe1_samples_menu(self):\n        """Register npe1 sample data, build menu and connect to events."""\n        plugin_manager.discover_sample_data()\n        plugin_manager.events.enabled.connect(_rebuild_npe1_samples_menu)\n        plugin_manager.events.disabled.connect(_rebuild_npe1_samples_menu)\n        plugin_manager.events.registered.connect(_rebuild_npe1_samples_menu)\n        plugin_manager.events.unregistered.connect(_rebuild_npe1_samples_menu)\n        _rebuild_npe1_samples_menu()\n\n    # TODO: Remove once npe1 deprecated\n    def _setup_npe1_plugins_menu(self):\n        """Register npe1 widgets, build menu and connect to events"""\n        plugin_manager.discover_widgets()\n        plugin_manager.events.registered.connect(_rebuild_npe1_plugins_menu)\n        plugin_manager.events.disabled.connect(_rebuild_npe1_plugins_menu)\n        plugin_manager.events.unregistered.connect(_rebuild_npe1_plugins_menu)\n        _rebuild_npe1_plugins_menu()\n\n    def _handle_trace_file_on_start(self):\n        """Start trace of `trace_file_on_start` config set."""\n        from napari._qt._qapp_model.qactions._debug import _start_trace\n\n        if perf.perf_config:\n            path = perf.perf_config.trace_file_on_start\n            if path is not None:\n                # Config option "trace_file_on_start" means immediately\n                # start tracing to that file. This is very useful if you\n                # want to create a trace every time you start napari,\n                # without having to start it from the debug menu.\n                _start_trace(path)\n\n    def _add_menus(self):\n        """Add menubar to napari app."""\n        # TODO: move this to _QMainWindow... but then all of the Menu()\n        # items will not have easy access to the methods on this Window obj.\n\n        self.main_menu = self._qt_window.menuBar()\n        # Menubar shortcuts are only active when the menubar is visible.\n        # Therefore, we set a global shortcut not associated with the menubar\n        # to toggle visibility, *but*, in order to not shadow the menubar\n        # shortcut, we disable it, and only enable it when the menubar is\n        # hidden. See this stackoverflow link for details:\n        # https://stackoverflow.com/questions/50537642/how-to-keep-the-shortcuts-of-a-hidden-widget-in-pyqt5\n        self._main_menu_shortcut = QShortcut(\'Ctrl+M\', self._qt_window)\n        self._main_menu_shortcut.setEnabled(False)\n        self._main_menu_shortcut.activated.connect(\n            self._toggle_menubar_visible\n        )\n        # file menu\n        self.file_menu = build_qmodel_menu(\n            MenuId.MENUBAR_FILE, title=trans._(\'&File\'), parent=self._qt_window\n        )\n        self._setup_npe1_samples_menu()\n        self.file_menu.aboutToShow.connect(\n            self._update_file_menu_state,\n        )\n        self.main_menu.addMenu(self.file_menu)\n        # view menu\n        self.view_menu = build_qmodel_menu(\n            MenuId.MENUBAR_VIEW, title=trans._(\'&View\'), parent=self._qt_window\n        )\n        self.view_menu.aboutToShow.connect(\n            self._update_view_menu_state,\n        )\n        self.main_menu.addMenu(self.view_menu)\n        # layers menu\n        self.layers_menu = build_qmodel_menu(\n            MenuId.MENUBAR_LAYERS,\n            title=trans._(\'&Layers\'),\n            parent=self._qt_window,\n        )\n        self.layers_menu.aboutToShow.connect(\n            self._update_layers_menu_state,\n        )\n        self.main_menu.addMenu(self.layers_menu)\n        # plugins menu\n        self.plugins_menu = build_qmodel_menu(\n            MenuId.MENUBAR_PLUGINS,\n            title=trans._(\'&Plugins\'),\n            parent=self._qt_window,\n        )\n        self._setup_npe1_plugins_menu()\n        self.plugins_menu.aboutToShow.connect(\n            self._update_plugins_menu_state,\n        )\n        self.main_menu.addMenu(self.plugins_menu)\n        # debug menu (optional)\n        if perf.perf_config is not None:\n            self._debug_menu = build_qmodel_menu(\n                MenuId.MENUBAR_DEBUG,\n                title=trans._(\'&Debug\'),\n                parent=self._qt_window,\n            )\n            self._handle_trace_file_on_start()\n            self._debug_menu.aboutToShow.connect(\n                self._update_debug_menu_state,\n            )\n            self.main_menu.addMenu(self._debug_menu)\n        # window menu\n        self.window_menu = build_qmodel_menu(\n            MenuId.MENUBAR_WINDOW,\n            title=trans._(\'&Window\'),\n            parent=self._qt_window,\n        )\n        self.plugins_menu.aboutToShow.connect(\n            self._update_window_menu_state,\n        )\n        self.main_menu.addMenu(self.window_menu)\n        # help menu\n        self.help_menu = build_qmodel_menu(\n            MenuId.MENUBAR_HELP, title=trans._(\'&Help\'), parent=self._qt_window\n        )\n        self.help_menu.aboutToShow.connect(\n            self._update_help_menu_state,\n        )\n        self.main_menu.addMenu(self.help_menu)\n\n    def _toggle_menubar_visible(self):\n        """Toggle visibility of app menubar.\n\n        This function also disables or enables a global keyboard shortcut to\n        show the menubar, since menubar shortcuts are only available while the\n        menubar is visible.\n        """\n        toggle_menubar_visibility = self._qt_window.toggle_menubar_visibility()\n        self._main_menu_shortcut.setEnabled(toggle_menubar_visibility)\n\n    def _toggle_fullscreen(self):\n        """Toggle fullscreen mode."""\n        if self._qt_window.isFullScreen():\n            self._qt_window.showNormal()\n        else:\n            self._qt_window.showFullScreen()\n\n    def _toggle_play(self):\n        """Toggle play."""\n        if self._qt_viewer.dims.is_playing:\n            self._qt_viewer.dims.stop()\n        else:\n            axis = self._qt_viewer.viewer.dims.last_used or 0\n            self._qt_viewer.dims.play(axis)\n\n    def add_plugin_dock_widget(\n        self,\n        plugin_name: str,\n        widget_name: Optional[str] = None,\n        tabify: bool = False,\n    ) -> tuple[QtViewerDockWidget, Any]:\n        """Add plugin dock widget if not already added.\n\n        Parameters\n        ----------\n        plugin_name : str\n            Name of a plugin providing a widget\n        widget_name : str, optional\n            Name of a widget provided by `plugin_name`. If `None`, and the\n            specified plugin provides only a single widget, that widget will be\n            returned, otherwise a ValueError will be raised, by default None\n        tabify : bool\n            Flag to tabify dock widget or not.\n\n        Returns\n        -------\n        tuple\n            A 2-tuple containing (the DockWidget instance, the plugin widget\n            instance).\n        """\n        from napari.plugins import _npe2\n\n        widget_class = None\n        dock_kwargs = {}\n\n        if result := _npe2.get_widget_contribution(plugin_name, widget_name):\n            widget_class, widget_name = result\n\n        if widget_class is None:\n            widget_class, dock_kwargs = plugin_manager.get_widget(\n                plugin_name, widget_name\n            )\n\n        if not widget_name:\n            # if widget_name wasn\'t provided, `get_widget` will have\n            # ensured that there is a single widget available.\n            widget_name = next(iter(plugin_manager._dock_widgets[plugin_name]))\n\n        full_name = plugin_menu_item_template.format(plugin_name, widget_name)\n        if full_name in self._dock_widgets:\n            dock_widget = self._dock_widgets[full_name]\n            wdg = dock_widget.widget()\n            if hasattr(wdg, \'_magic_widget\'):\n                wdg = wdg._magic_widget\n            return dock_widget, wdg\n\n        wdg = _instantiate_dock_widget(\n            widget_class, cast(\'Viewer\', self._qt_viewer.viewer)\n        )\n\n        # Add dock widget\n        dock_kwargs.pop(\'name\', None)\n        dock_widget = self.add_dock_widget(\n            wdg, name=full_name, tabify=tabify, **dock_kwargs\n        )\n        return dock_widget, wdg\n\n    def _add_plugin_function_widget(self, plugin_name: str, widget_name: str):\n        """Add plugin function widget if not already added.\n\n        Parameters\n        ----------\n        plugin_name : str\n            Name of a plugin providing a widget\n        widget_name : str, optional\n            Name of a widget provided by `plugin_name`. If `None`, and the\n            specified plugin provides only a single widget, that widget will be\n            returned, otherwise a ValueError will be raised, by default None\n        """\n        full_name = plugin_menu_item_template.format(plugin_name, widget_name)\n        if full_name in self._dock_widgets:\n            return None\n\n        func = plugin_manager._function_widgets[plugin_name][widget_name]\n\n        # Add function widget\n        return self.add_function_widget(\n            func, name=full_name, area=None, allowed_areas=None\n        )\n\n    def add_dock_widget(\n        self,\n        widget: Union[QWidget, \'Widget\'],\n        *,\n        name: str = \'\',\n        area: str = \'right\',\n        allowed_areas: Optional[Sequence[str]] = None,\n        shortcut=_sentinel,\n        add_vertical_stretch=True,\n        tabify: bool = False,\n        menu: Optional[QMenu] = None,\n    ):\n        """Convenience method to add a QDockWidget to the main window.\n\n        If name is not provided a generic name will be addded to avoid\n        `saveState` warnings on close.\n\n        Parameters\n        ----------\n        widget : QWidget\n            `widget` will be added as QDockWidget\'s main widget.\n        name : str, optional\n            Name of dock widget to appear in window menu.\n        area : str\n            Side of the main window to which the new dock widget will be added.\n            Must be in {\'left\', \'right\', \'top\', \'bottom\'}\n        allowed_areas : list[str], optional\n            Areas, relative to the main window, that the widget is allowed dock.\n            Each item in list must be in {\'left\', \'right\', \'top\', \'bottom\'}\n            By default, all areas are allowed.\n        shortcut : str, optional\n            Keyboard shortcut to appear in dropdown menu.\n        add_vertical_stretch : bool, optional\n            Whether to add stretch to the bottom of vertical widgets (pushing\n            widgets up towards the top of the allotted area, instead of letting\n            them distribute across the vertical space).  By default, True.\n\n            .. deprecated:: 0.4.8\n\n                The shortcut parameter is deprecated since version 0.4.8, please use\n                the action and shortcut manager APIs. The new action manager and\n                shortcut API allow user configuration and localization.\n        tabify : bool\n            Flag to tabify dock widget or not.\n        menu : QMenu, optional\n            Menu bar to add toggle action to. If `None` nothing added to menu.\n\n        Returns\n        -------\n        dock_widget : QtViewerDockWidget\n            `dock_widget` that can pass viewer events.\n        """\n        if not name:\n            with contextlib.suppress(AttributeError):\n                name = widget.objectName()\n            name = name or trans._(\n                \'Dock widget {number}\',\n                number=self._unnamed_dockwidget_count,\n            )\n\n            self._unnamed_dockwidget_count += 1\n\n        if shortcut is not _sentinel:\n            warnings.warn(\n                _SHORTCUT_DEPRECATION_STRING.format(shortcut=shortcut),\n                FutureWarning,\n                stacklevel=2,\n            )\n            dock_widget = QtViewerDockWidget(\n                self._qt_viewer,\n                widget,\n                name=name,\n                area=area,\n                allowed_areas=allowed_areas,\n                shortcut=shortcut,\n                add_vertical_stretch=add_vertical_stretch,\n            )\n        else:\n            dock_widget = QtViewerDockWidget(\n                self._qt_viewer,\n                widget,\n                name=name,\n                area=area,\n                allowed_areas=allowed_areas,\n                add_vertical_stretch=add_vertical_stretch,\n            )\n\n        self._add_viewer_dock_widget(dock_widget, tabify=tabify, menu=menu)\n\n        if hasattr(widget, \'reset_choices\'):\n            # Keep the dropdown menus in the widget in sync with the layer model\n            # if widget has a `reset_choices`, which is true for all magicgui\n            # `CategoricalWidget`s\n            layers_events = self._qt_viewer.viewer.layers.events\n            layers_events.inserted.connect(widget.reset_choices)\n            layers_events.removed.connect(widget.reset_choices)\n            layers_events.reordered.connect(widget.reset_choices)\n\n        # Add dock widget to dictionary\n        self._dock_widgets[dock_widget.name] = dock_widget\n\n        return dock_widget\n\n    def _add_viewer_dock_widget(\n        self,\n        dock_widget: QtViewerDockWidget,\n        tabify: bool = False,\n        menu: Optional[QMenu] = None,\n    ):\n        """Add a QtViewerDockWidget to the main window\n\n        If other widgets already present in area then will tabify.\n\n        Parameters\n        ----------\n        dock_widget : QtViewerDockWidget\n            `dock_widget` will be added to the main window.\n        tabify : bool\n            Flag to tabify dockwidget or not.\n        menu : QMenu, optional\n            Menu bar to add toggle action to. If `None` nothing added to menu.\n        """\n        # Find if any othe dock widgets are currently in area\n        current_dws_in_area = [\n            dw\n            for dw in self._qt_window.findChildren(QDockWidget)\n            if self._qt_window.dockWidgetArea(dw) == dock_widget.qt_area\n        ]\n        self._qt_window.addDockWidget(dock_widget.qt_area, dock_widget)\n\n        # If another dock widget present in area then tabify\n        if current_dws_in_area:\n            if tabify:\n                self._qt_window.tabifyDockWidget(\n                    current_dws_in_area[-1], dock_widget\n                )\n                dock_widget.show()\n                dock_widget.raise_()\n            elif dock_widget.area in (\'right\', \'left\'):\n                _wdg = [*current_dws_in_area, dock_widget]\n                # add sizes to push lower widgets up\n                sizes = list(range(1, len(_wdg) * 4, 4))\n                self._qt_window.resizeDocks(\n                    _wdg, sizes, Qt.Orientation.Vertical\n                )\n\n        if menu:\n            action = dock_widget.toggleViewAction()\n            action.setStatusTip(dock_widget.name)\n            action.setText(dock_widget.name)\n            import warnings\n\n            with warnings.catch_warnings():\n                warnings.simplefilter(\'ignore\', FutureWarning)\n                # deprecating with 0.4.8, but let\'s try to keep compatibility.\n                shortcut = dock_widget.shortcut\n            if shortcut is not None:\n                action.setShortcut(shortcut)\n\n            menu.addAction(action)\n\n        # see #3663, to fix #3624 more generally\n        dock_widget.setFloating(False)\n\n    def _remove_dock_widget(self, event) -> None:\n        names = list(self._dock_widgets.keys())\n        for widget_name in names:\n            if event.value in widget_name:\n                # remove this widget\n                widget = self._dock_widgets[widget_name]\n                self.remove_dock_widget(widget)\n\n    def remove_dock_widget(self, widget: QWidget, menu=None):\n        """Removes specified dock widget.\n\n        If a QDockWidget is not provided, the existing QDockWidgets will be\n        searched for one whose inner widget (``.widget()``) is the provided\n        ``widget``.\n\n        Parameters\n        ----------\n        widget : QWidget | str\n            If widget == \'all\', all docked widgets will be removed.\n        menu : QMenu, optional\n            Menu bar to remove toggle action from. If `None` nothing removed\n            from menu.\n        """\n        if widget == \'all\':\n            for dw in list(self._dock_widgets.values()):\n                self.remove_dock_widget(dw)\n            return\n\n        if not isinstance(widget, QDockWidget):\n            dw: QDockWidget\n            for dw in self._qt_window.findChildren(QDockWidget):\n                if dw.widget() is widget:\n                    _dw: QDockWidget = dw\n                    break\n            else:\n                raise LookupError(\n                    trans._(\n                        \'Could not find a dock widget containing: {widget}\',\n                        deferred=True,\n                        widget=widget,\n                    )\n                )\n        else:\n            _dw = widget\n\n        if _dw.widget():\n            _dw.widget().setParent(None)\n        self._qt_window.removeDockWidget(_dw)\n        if menu is not None:\n            menu.removeAction(_dw.toggleViewAction())\n\n        # Remove dock widget from dictionary\n        self._dock_widgets.pop(_dw.name, None)\n\n        # Deleting the dock widget means any references to it will no longer\n        # work but it\'s not really useful anyway, since the inner widget has\n        # been removed. and anyway: people should be using add_dock_widget\n        # rather than directly using _add_viewer_dock_widget\n        _dw.deleteLater()\n\n    def add_function_widget(\n        self,\n        function,\n        *,\n        magic_kwargs=None,\n        name: str = \'\',\n        area=None,\n        allowed_areas=None,\n        shortcut=_sentinel,\n    ):\n        """Turn a function into a dock widget via magicgui.\n\n        Parameters\n        ----------\n        function : callable\n            Function that you want to add.\n        magic_kwargs : dict, optional\n            Keyword arguments to :func:`magicgui.magicgui` that\n            can be used to specify widget.\n        name : str, optional\n            Name of dock widget to appear in window menu.\n        area : str, optional\n            Side of the main window to which the new dock widget will be added.\n            Must be in {\'left\', \'right\', \'top\', \'bottom\'}. If not provided the\n            default will be determined by the widget.layout, with \'vertical\'\n            layouts appearing on the right, otherwise on the bottom.\n        allowed_areas : list[str], optional\n            Areas, relative to main window, that the widget is allowed dock.\n            Each item in list must be in {\'left\', \'right\', \'top\', \'bottom\'}\n            By default, only provided areas is allowed.\n        shortcut : str, optional\n            Keyboard shortcut to appear in dropdown menu.\n\n        Returns\n        -------\n        dock_widget : QtViewerDockWidget\n            `dock_widget` that can pass viewer events.\n        """\n        from magicgui import magicgui\n\n        if magic_kwargs is None:\n            magic_kwargs = {\n                \'auto_call\': False,\n                \'call_button\': \'run\',\n                \'layout\': \'vertical\',\n            }\n\n        widget = magicgui(function, **magic_kwargs or {})\n\n        if area is None:\n            area = \'right\' if str(widget.layout) == \'vertical\' else \'bottom\'\n        if allowed_areas is None:\n            allowed_areas = [area]\n        if shortcut is not _sentinel:\n            return self.add_dock_widget(\n                widget,\n                name=name or function.__name__.replace(\'_\', \' \'),\n                area=area,\n                allowed_areas=allowed_areas,\n                shortcut=shortcut,\n            )\n\n        return self.add_dock_widget(\n            widget,\n            name=name or function.__name__.replace(\'_\', \' \'),\n            area=area,\n            allowed_areas=allowed_areas,\n        )\n\n    def resize(self, width, height):\n        """Resize the window.\n\n        Parameters\n        ----------\n        width : int\n            Width in logical pixels.\n        height : int\n            Height in logical pixels.\n        """\n        self._qt_window.resize(width, height)\n\n    def set_geometry(self, left, top, width, height):\n        """Set the geometry of the widget\n\n        Parameters\n        ----------\n        left : int\n            X coordinate of the upper left border.\n        top : int\n            Y coordinate of the upper left border.\n        width : int\n            Width of the rectangle shape of the window.\n        height : int\n            Height of the rectangle shape of the window.\n        """\n        self._qt_window.setGeometry(left, top, width, height)\n\n    def geometry(self) -> tuple[int, int, int, int]:\n        """Get the geometry of the widget\n\n        Returns\n        -------\n        left : int\n            X coordinate of the upper left border.\n        top : int\n            Y coordinate of the upper left border.\n        width : int\n            Width of the rectangle shape of the window.\n        height : int\n            Height of the rectangle shape of the window.\n        """\n        rect = self._qt_window.geometry()\n        return rect.left(), rect.top(), rect.width(), rect.height()\n\n    def show(self, *, block=False):\n        """Resize, show, and bring forward the window.\n\n        Raises\n        ------\n        RuntimeError\n            If the viewer.window has already been closed and deleted.\n        """\n        settings = get_settings()\n        try:\n            self._qt_window.show(block=block)\n        except (AttributeError, RuntimeError) as e:\n            raise RuntimeError(\n                trans._(\n                    \'This viewer has already been closed and deleted. Please create a new one.\',\n                    deferred=True,\n                )\n            ) from e\n\n        if settings.application.first_time:\n            settings.application.first_time = False\n            try:\n                self._qt_window.resize(self._qt_window.layout().sizeHint())\n            except (AttributeError, RuntimeError) as e:\n                raise RuntimeError(\n                    trans._(\n                        \'This viewer has already been closed and deleted. Please create a new one.\',\n                        deferred=True,\n                    )\n                ) from e\n        else:\n            try:\n                if settings.application.save_window_geometry:\n                    self._qt_window._set_window_settings(\n                        *self._qt_window._load_window_settings()\n                    )\n            except Exception as err:  # noqa: BLE001\n                import warnings\n\n                warnings.warn(\n                    trans._(\n                        \'The window geometry settings could not be loaded due to the following error: {err}\',\n                        deferred=True,\n                        err=err,\n                    ),\n                    category=RuntimeWarning,\n                    stacklevel=2,\n                )\n\n        # Resize axis labels now that window is shown\n        self._qt_viewer.dims._resize_axis_labels()\n\n        # We want to bring the viewer to the front when\n        # A) it is our own event loop OR we are running in jupyter\n        # B) it is not the first time a QMainWindow is being created\n\n        # `app_name` will be "napari" iff the application was instantiated in\n        # get_app(). isActiveWindow() will be True if it is the second time a\n        # _qt_window has been created.\n        # See #721, #732, #735, #795, #1594\n        app_name = QApplication.instance().applicationName()\n        if (\n            app_name == \'napari\' or in_jupyter()\n        ) and self._qt_window.isActiveWindow():\n            self.activate()\n\n    def activate(self):\n        """Make the viewer the currently active window."""\n        self._qt_window.raise_()  # for macOS\n        self._qt_window.activateWindow()  # for Windows\n\n    def _update_theme_no_event(self):\n        self._update_theme()\n\n    def _update_theme_font_size(self, event=None):\n        settings = get_settings()\n        font_size = event.value if event else settings.appearance.font_size\n        extra_variables = {\'font_size\': f\'{font_size}pt\'}\n        self._update_theme(extra_variables=extra_variables)\n\n    def _update_theme(self, event=None, extra_variables=None):\n        """Update widget color theme."""\n        if extra_variables is None:\n            extra_variables = {}\n        settings = get_settings()\n        with contextlib.suppress(AttributeError, RuntimeError):\n            value = event.value if event else settings.appearance.theme\n            self._qt_viewer.viewer.theme = value\n            actual_theme_name = value\n            if value == \'system\':\n                # system isn\'t a theme, so get the name\n                actual_theme_name = get_system_theme()\n            # check `font_size` value is always passed when updating style\n            if \'font_size\' not in extra_variables:\n                extra_variables.update(\n                    {\'font_size\': f\'{settings.appearance.font_size}pt\'}\n                )\n            # set the style sheet with the theme name and extra_variables\n            self._qt_window.setStyleSheet(\n                get_stylesheet(\n                    actual_theme_name, extra_variables=extra_variables\n                )\n            )\n\n    def _status_changed(self, event):\n        """Update status bar.\n\n        Parameters\n        ----------\n        event : napari.utils.event.Event\n            The napari event that triggered this method.\n        """\n        if isinstance(event.value, str):\n            self._status_bar.setStatusText(event.value)\n        else:\n            status_info = event.value\n            self._status_bar.setStatusText(\n                layer_base=status_info[\'layer_base\'],\n                source_type=status_info[\'source_type\'],\n                plugin=status_info[\'plugin\'],\n                coordinates=status_info[\'coordinates\'],\n            )\n\n    def _title_changed(self, event):\n        """Update window title.\n\n        Parameters\n        ----------\n        event : napari.utils.event.Event\n            The napari event that triggered this method.\n        """\n        self._qt_window.setWindowTitle(event.value)\n\n    def _help_changed(self, event):\n        """Update help message on status bar.\n\n        Parameters\n        ----------\n        event : napari.utils.event.Event\n            The napari event that triggered this method.\n        """\n        self._status_bar.setHelpText(event.value)\n\n    def _restart(self):\n        """Restart the napari application."""\n        self._qt_window.restart()\n\n    def _screenshot(\n        self, size=None, scale=None, flash=True, canvas_only=False\n    ) -> \'QImage\':\n        """Capture screenshot of the currently displayed viewer.\n\n        Parameters\n        ----------\n        flash : bool\n            Flag to indicate whether flash animation should be shown after\n            the screenshot was captured.\n        size : tuple (int, int)\n            Size (resolution height x width) of the screenshot. By default, the currently displayed size.\n            Only used if `canvas_only` is True.\n        scale : float\n            Scale factor used to increase resolution of canvas for the screenshot.\n            By default, the currently displayed resolution.\n            Only used if `canvas_only` is True.\n        canvas_only : bool\n            If True, screenshot shows only the image display canvas, and\n            if False include the napari viewer frame in the screenshot,\n            By default, True.\n\n        Returns\n        -------\n        img : QImage\n        """\n        from napari._qt.utils import add_flash_animation\n\n        if canvas_only:\n            canvas = self._qt_viewer.canvas\n            prev_size = canvas.size\n            if size is not None:\n                if len(size) != 2:\n                    raise ValueError(\n                        trans._(\n                            \'screenshot size must be 2 values, got {len_size}\',\n                            len_size=len(size),\n                        )\n                    )\n                # Scale the requested size to account for HiDPI\n                size = tuple(\n                    int(dim / self._qt_window.devicePixelRatio())\n                    for dim in size\n                )\n                canvas.size = size\n            if scale is not None:\n                # multiply canvas dimensions by the scale factor to get new size\n                canvas.size = tuple(int(dim * scale) for dim in canvas.size)\n            try:\n                img = canvas.screenshot()\n                if flash:\n                    add_flash_animation(self._qt_viewer._welcome_widget)\n            finally:\n                # make sure we always go back to the right canvas size\n                if size is not None or scale is not None:\n                    canvas.size = prev_size\n        else:\n            img = self._qt_window.grab().toImage()\n            if flash:\n                add_flash_animation(self._qt_window)\n        return img\n\n    def screenshot(\n        self, path=None, size=None, scale=None, flash=True, canvas_only=False\n    ):\n        """Take currently displayed viewer and convert to an image array.\n\n        Parameters\n        ----------\n        path : str\n            Filename for saving screenshot image.\n        size : tuple (int, int)\n            Size (resolution) of the screenshot. By default, the currently displayed size.\n            Only used if `canvas_only` is True.\n        scale : float\n            Scale factor used to increase resolution of canvas for the screenshot.\n            By default, the currently displayed resolution.\n            Only used if `canvas_only` is True.\n        flash : bool\n            Flag to indicate whether flash animation should be shown after\n            the screenshot was captured.\n        canvas_only : bool\n            If True, screenshot shows only the image display canvas, and\n            if False includes the napari viewer frame in the screenshot,\n            By default, True.\n\n        Returns\n        -------\n        image : array\n            Numpy array of type ubyte and shape (h, w, 4). Index [0, 0] is the\n            upper-left corner of the rendered region.\n        """\n\n        img = QImg2array(self._screenshot(size, scale, flash, canvas_only))\n        if path is not None:\n            imsave(path, img)\n        return img\n\n    def clipboard(self, flash=True, canvas_only=False):\n        """Copy screenshot of current viewer to the clipboard.\n\n        Parameters\n        ----------\n        flash : bool\n            Flag to indicate whether flash animation should be shown after\n            the screenshot was captured.\n        canvas_only : bool\n            If True, screenshot shows only the image display canvas, and\n            if False include the napari viewer frame in the screenshot,\n            By default, True.\n        """\n        img = self._screenshot(flash=flash, canvas_only=canvas_only)\n        QApplication.clipboard().setImage(img)\n\n    def _teardown(self):\n        """Carry out various teardown tasks such as event disconnection."""\n        self._setup_existing_themes(False)\n        _themes.events.added.disconnect(self._add_theme)\n        _themes.events.removed.disconnect(self._remove_theme)\n\n    def close(self):\n        """Close the viewer window and cleanup sub-widgets."""\n        # Someone is closing us twice? Only try to delete self._qt_window\n        # if we still have one.\n        if hasattr(self, \'_qt_window\'):\n            self._teardown()\n            self._qt_viewer.close()\n            self._qt_window.close()\n            del self._qt_window\n\n    def _open_preferences_dialog(self) -> PreferencesDialog:\n        """Edit preferences from the menubar."""\n        if self._pref_dialog is None:\n            win = PreferencesDialog(parent=self._qt_window)\n            self._pref_dialog = win\n\n            app_pref = get_settings().application\n            if app_pref.preferences_size:\n                win.resize(*app_pref.preferences_size)\n\n            @win.resized.connect\n            def _save_size(sz: QSize):\n                app_pref.preferences_size = (sz.width(), sz.height())\n\n            def _clean_pref_dialog():\n                self._pref_dialog = None\n\n            win.finished.connect(_clean_pref_dialog)\n            win.show()\n        else:\n            self._pref_dialog.raise_()\n\n        return self._pref_dialog\n\n    def _screenshot_dialog(self):\n        """Save screenshot of current display with viewer, default .png"""\n        from napari._qt.dialogs.screenshot_dialog import ScreenshotDialog\n        from napari.utils.history import get_save_history, update_save_history\n\n        hist = get_save_history()\n        dial = ScreenshotDialog(\n            self.screenshot, self._qt_viewer, hist[0], hist\n        )\n        if dial.exec_():\n            update_save_history(dial.selectedFiles()[0])\n\n\ndef _instantiate_dock_widget(wdg_cls, viewer: \'Viewer\'):\n    # if the signature is looking a for a napari viewer, pass it.\n    from napari.viewer import Viewer\n\n    kwargs = {}\n    try:\n        sig = inspect.signature(wdg_cls.__init__)\n    # Inspection can fail when adding to bundle as it thinks widget is a builtin\n    except ValueError:\n        pass\n    else:\n        for param in sig.parameters.values():\n            if param.name == \'napari_viewer\':\n                kwargs[\'napari_viewer\'] = PublicOnlyProxy(viewer)\n                break\n            if param.annotation in (\'napari.viewer.Viewer\', Viewer):\n                kwargs[param.name] = PublicOnlyProxy(viewer)\n                break\n            # cannot look for param.kind == param.VAR_KEYWORD because\n            # QWidget allows **kwargs but errs on unknown keyword arguments\n\n    # instantiate the widget\n    return wdg_cls(**kwargs)\n',
        }
